import { TopicContent } from "./topicContent";

export const machineLearningTopics: TopicContent[] = [
  { title: "Linear Regression", theory: "Linear regression models the relationship between a dependent variable and one or more independent variables by fitting a linear equation. The goal is to minimize the sum of squared residuals (ordinary least squares).\n\nSimple linear regression: y = mx + b. Multiple linear regression: y = β₀ + β₁x₁ + β₂x₂ + ... Assumptions: linearity, independence, homoscedasticity (constant variance), normality of residuals. Gradient descent iteratively optimizes parameters. R² measures how well the model explains variance.", keyPoints: ["y = β₀ + β₁x₁ + ... + βₙxₙ + ε", "OLS minimizes sum of squared residuals", "R²: proportion of variance explained (0 to 1)", "Gradient descent: iterative optimization", "Assumptions: linearity, independence, normal residuals"], codeExample: { language: "python", code: `import numpy as np\n\nclass LinearRegression:\n    def __init__(self, lr=0.01, epochs=1000):\n        self.lr = lr\n        self.epochs = epochs\n    \n    def fit(self, X, y):\n        self.weights = np.zeros(X.shape[1])\n        self.bias = 0\n        m = len(y)\n        \n        for _ in range(self.epochs):\n            y_pred = X @ self.weights + self.bias\n            error = y_pred - y\n            self.weights -= self.lr * (2/m) * (X.T @ error)\n            self.bias -= self.lr * (2/m) * np.sum(error)\n    \n    def predict(self, X):\n        return X @ self.weights + self.bias\n    \n    def r_squared(self, X, y):\n        y_pred = self.predict(X)\n        ss_res = np.sum((y - y_pred) ** 2)\n        ss_tot = np.sum((y - np.mean(y)) ** 2)\n        return 1 - ss_res / ss_tot`, explanation: "Linear regression from scratch using gradient descent — the foundation of ML optimization." }, handsOn: [{ task: "Implement linear regression and predict house prices based on features.", hint: "Use features like area, bedrooms, location. Normalize features before training." }, { task: "Visualize the cost function convergence during gradient descent training.", hint: "Track MSE at each epoch and plot it — should decrease monotonically." }, { task: "Compare OLS closed-form solution with gradient descent results.", hint: "Closed form: θ = (XᵀX)⁻¹Xᵀy. Both should give similar results." }] },
  { title: "Logistic Regression", theory: "Logistic regression is a classification algorithm that models the probability of a binary outcome using the sigmoid function: σ(z) = 1/(1+e^(-z)). Despite its name, it's used for classification, not regression.\n\nThe decision boundary is where P(y=1|x) = 0.5. Cost function uses cross-entropy loss (log loss) instead of MSE. Regularization (L1/L2) prevents overfitting. Multi-class: One-vs-Rest (OvR) or softmax regression. ROC curve and AUC measure classifier performance.", keyPoints: ["Sigmoid function maps linear output to probability [0,1]", "Cross-entropy loss: -[y·log(ŷ) + (1-y)·log(1-ŷ)]", "Decision boundary: linear separator in feature space", "Regularization: L1 (Lasso) for sparsity, L2 (Ridge) for stability", "AUC-ROC measures discrimination ability"], codeExample: { language: "python", code: `import numpy as np\n\ndef sigmoid(z):\n    return 1 / (1 + np.exp(-z))\n\nclass LogisticRegression:\n    def __init__(self, lr=0.01, epochs=1000):\n        self.lr = lr\n        self.epochs = epochs\n    \n    def fit(self, X, y):\n        m, n = X.shape\n        self.weights = np.zeros(n)\n        self.bias = 0\n        \n        for _ in range(self.epochs):\n            z = X @ self.weights + self.bias\n            y_pred = sigmoid(z)\n            dw = (1/m) * X.T @ (y_pred - y)\n            db = (1/m) * np.sum(y_pred - y)\n            self.weights -= self.lr * dw\n            self.bias -= self.lr * db\n    \n    def predict(self, X, threshold=0.5):\n        probs = sigmoid(X @ self.weights + self.bias)\n        return (probs >= threshold).astype(int)`, explanation: "Logistic regression from scratch — binary classification using sigmoid and cross-entropy optimization." }, handsOn: [{ task: "Build a spam classifier using logistic regression on email features.", hint: "Features: word frequencies, email length, number of links. Binary output: spam/not spam." }, { task: "Plot the ROC curve and calculate AUC for your classifier.", hint: "Vary threshold from 0 to 1; plot TPR vs FPR at each threshold." }] },
  { title: "Decision Trees", theory: "Decision trees split data recursively based on feature values to make predictions. Each internal node tests a feature, branches represent outcomes, and leaves represent predictions.\n\nSplitting criteria: Gini impurity (CART) measures class mixture, Information Gain/Entropy (ID3/C4.5) measures information reduction. Trees are prone to overfitting — solved by pruning (pre-pruning: max depth, min samples; post-pruning: cost-complexity). Advantages: interpretable, handles non-linear relationships, no feature scaling needed.", keyPoints: ["Gini impurity: 1 - Σ(pᵢ²), measures class impurity", "Information gain: entropy before - weighted entropy after split", "Prone to overfitting → use pruning", "No feature scaling needed", "Handles both numerical and categorical features"], codeExample: { language: "python", code: `import numpy as np\nfrom collections import Counter\n\ndef gini(y):\n    counts = Counter(y)\n    total = len(y)\n    return 1 - sum((c/total)**2 for c in counts.values())\n\ndef best_split(X, y):\n    best_gain, best_feat, best_val = -1, None, None\n    parent_gini = gini(y)\n    \n    for feat in range(X.shape[1]):\n        thresholds = np.unique(X[:, feat])\n        for val in thresholds:\n            left = y[X[:, feat] <= val]\n            right = y[X[:, feat] > val]\n            if len(left) == 0 or len(right) == 0:\n                continue\n            weighted = (len(left)*gini(left) + len(right)*gini(right)) / len(y)\n            gain = parent_gini - weighted\n            if gain > best_gain:\n                best_gain, best_feat, best_val = gain, feat, val\n    \n    return best_feat, best_val, best_gain\n\nprint("Best split:", best_split(\n    np.array([[1],[2],[3],[4],[5]]),\n    np.array([0, 0, 1, 1, 1])\n))`, explanation: "Finding the best split point using Gini impurity — the core of decision tree construction." }, handsOn: [{ task: "Build a decision tree classifier from scratch and visualize the tree structure.", hint: "Recursively find best split; stop at max depth or pure leaf." }, { task: "Compare Gini vs Entropy splitting criteria on a dataset.", hint: "Train two trees with different criteria; compare accuracy and tree depth." }] },
  { title: "Random Forests", theory: "Random Forest is an ensemble of decision trees, each trained on a random bootstrap sample of data with a random subset of features. Predictions are aggregated by majority vote (classification) or averaging (regression).\n\nBagging (Bootstrap Aggregating) reduces variance by averaging multiple models. Feature randomness further decorrelates trees. Out-of-bag (OOB) error provides validation without a separate test set. Feature importance measures how much each feature reduces impurity across all trees. Typically, √n features per split for classification, n/3 for regression.", keyPoints: ["Ensemble of decision trees with bagging", "Random feature subset at each split decorrelates trees", "Reduces overfitting compared to single decision tree", "OOB error: built-in cross-validation", "Feature importance: average impurity decrease across trees"], handsOn: [{ task: "Train a Random Forest and compare its accuracy to a single decision tree.", hint: "Use sklearn's RandomForestClassifier; vary n_estimators and max_features." }, { task: "Analyze feature importance scores and select the top features.", hint: "Access .feature_importances_ attribute; plot sorted importances." }] },
  { title: "SVM", theory: "Support Vector Machines find the optimal hyperplane that maximizes the margin between classes. Support vectors are the closest points to the decision boundary.\n\nLinear SVM works when data is linearly separable. The kernel trick maps data to higher dimensions for non-linear separation: polynomial kernel, RBF (Gaussian) kernel. C parameter controls the trade-off between margin size and misclassification. Soft margin allows some misclassification. SVMs are effective in high-dimensional spaces.", keyPoints: ["Maximize margin between classes", "Support vectors: points closest to the boundary", "Kernel trick: project to higher dimensions for non-linear separation", "RBF kernel: most commonly used for non-linear SVM", "C parameter: balance margin width vs classification errors"], handsOn: [{ task: "Train SVM classifiers with different kernels (linear, RBF, polynomial) and compare.", hint: "Use sklearn's SVC; vary kernel parameter; plot decision boundaries." }, { task: "Tune C and gamma parameters using grid search with cross-validation.", hint: "GridSearchCV with param_grid = {'C': [0.1, 1, 10], 'gamma': [0.01, 0.1, 1]}." }] },
  { title: "K-Means Clustering", theory: "K-Means is an unsupervised algorithm that partitions data into k clusters by minimizing within-cluster sum of squares. Algorithm: initialize k centroids → assign points to nearest centroid → update centroids → repeat until convergence.\n\nInitialization matters: K-Means++ provides better starting centroids. Elbow method helps choose k: plot inertia vs k, find the 'elbow'. Silhouette score measures cluster quality. Limitations: assumes spherical clusters, sensitive to outliers, requires specifying k. Alternatives: DBSCAN, hierarchical clustering, GMM.", keyPoints: ["Iterative: assign to nearest centroid → update centroids", "K-Means++ improves initialization", "Elbow method: plot inertia vs k to find optimal k", "Silhouette score: measures cluster separation quality", "Assumes spherical, equal-size clusters"], codeExample: { language: "python", code: `import numpy as np\n\ndef kmeans(X, k, max_iters=100):\n    # K-Means++ initialization\n    centroids = [X[np.random.randint(len(X))]]\n    for _ in range(1, k):\n        dists = np.array([min(np.linalg.norm(x - c)**2 for c in centroids) for x in X])\n        probs = dists / dists.sum()\n        centroids.append(X[np.random.choice(len(X), p=probs)])\n    centroids = np.array(centroids)\n    \n    for _ in range(max_iters):\n        # Assign clusters\n        labels = np.argmin(np.linalg.norm(X[:, None] - centroids, axis=2), axis=1)\n        # Update centroids\n        new_centroids = np.array([X[labels == i].mean(axis=0) for i in range(k)])\n        if np.allclose(centroids, new_centroids):\n            break\n        centroids = new_centroids\n    \n    return labels, centroids`, explanation: "K-Means with K-Means++ initialization — smarter starting points lead to better convergence." }, handsOn: [{ task: "Implement K-Means from scratch and cluster a 2D dataset, visualizing results.", hint: "Generate blobs with make_blobs; run K-Means; color points by cluster; plot centroids." }, { task: "Use the elbow method and silhouette analysis to find the optimal number of clusters.", hint: "Run K-Means for k=2 to 10; plot inertia and average silhouette score." }] },
  { title: "PCA", theory: "Principal Component Analysis reduces dimensionality by projecting data onto orthogonal axes (principal components) that capture maximum variance. It's used for visualization, noise reduction, and feature compression.\n\nSteps: standardize data → compute covariance matrix → find eigenvectors/eigenvalues → sort by eigenvalue → project onto top k eigenvectors. The explained variance ratio shows how much information each component captures. PCA is linear; for non-linear reduction, use t-SNE or UMAP.", keyPoints: ["Finds directions of maximum variance", "Eigenvectors of covariance matrix = principal components", "Explained variance ratio guides choosing k components", "Standardize features before PCA", "Linear method — use t-SNE/UMAP for non-linear"], handsOn: [{ task: "Apply PCA to reduce a high-dimensional dataset to 2D and visualize clusters.", hint: "Standardize, fit PCA(n_components=2), scatter plot with class colors." }, { task: "Implement PCA from scratch using eigendecomposition of the covariance matrix.", hint: "Center data, compute X.T @ X / n, numpy.linalg.eigh, sort descending, project." }] },
  { title: "Ensemble Methods", theory: "Ensemble methods combine multiple models for better performance than any single model. Bagging (parallel, reduces variance): Random Forest. Boosting (sequential, reduces bias): AdaBoost, Gradient Boosting, XGBoost, LightGBM.\n\nAdaBoost adjusts sample weights — misclassified samples get higher weight. Gradient Boosting fits new models to the residual errors of previous models. XGBoost adds regularization and parallel tree construction. Stacking uses a meta-learner to combine base model predictions. Voting combines different algorithms.", keyPoints: ["Bagging: parallel training, reduces variance (Random Forest)", "Boosting: sequential training, reduces bias (XGBoost)", "AdaBoost: weight misclassified samples higher", "Gradient Boosting: fit residuals of previous models", "XGBoost/LightGBM: optimized gradient boosting implementations"], handsOn: [{ task: "Compare Random Forest, AdaBoost, and XGBoost on a classification task.", hint: "Use sklearn's ensemble module and xgboost; compare accuracy, training time, overfitting." }, { task: "Build a stacking ensemble that combines different base classifiers.", hint: "Train base models; use their predictions as features for a meta-classifier." }] },
  { title: "Model Evaluation", theory: "Model evaluation measures how well a model generalizes to unseen data. Metrics depend on the task: classification (accuracy, precision, recall, F1), regression (MSE, RMSE, MAE, R²).\n\nCross-validation provides robust evaluation: k-fold splits data into k parts, trains on k-1, tests on 1, rotates. Stratified k-fold maintains class proportions. Confusion matrix: TP, FP, TN, FN. Precision = TP/(TP+FP), Recall = TP/(TP+FN). ROC-AUC for ranking. Learning curves diagnose bias/variance.", keyPoints: ["Confusion matrix: TP, FP, TN, FN", "Precision: of predicted positives, how many are correct", "Recall: of actual positives, how many were found", "F1-score: harmonic mean of precision and recall", "K-fold cross-validation for robust evaluation"], handsOn: [{ task: "Calculate precision, recall, F1-score, and plot a confusion matrix for a classifier.", hint: "Use sklearn's classification_report and ConfusionMatrixDisplay." }, { task: "Plot learning curves (train vs validation error) to diagnose underfitting/overfitting.", hint: "Train with increasing data sizes; high train error = underfit; gap = overfit." }] },
  { title: "Bias-Variance Tradeoff", theory: "The bias-variance tradeoff is the fundamental tension in ML. Bias: error from overly simple assumptions (underfitting). Variance: error from sensitivity to training data fluctuations (overfitting). Total error = Bias² + Variance + Irreducible noise.\n\nHigh bias (underfit): model too simple, poor performance on both train and test. High variance (overfit): model too complex, great on train, poor on test. Sweet spot: minimize total error. Regularization, ensemble methods, and proper model complexity selection manage this tradeoff.", keyPoints: ["Bias: systematic error from wrong assumptions", "Variance: error from sensitivity to training data", "Total error = Bias² + Variance + Noise", "Underfit: high bias, low variance", "Overfit: low bias, high variance"], handsOn: [{ task: "Demonstrate the bias-variance tradeoff by varying polynomial regression degree.", hint: "Fit polynomials of degree 1, 3, 10, 20; plot train/test error vs complexity." }, { task: "Show how regularization strength affects bias and variance.", hint: "Vary lambda in Ridge regression; plot train/test MSE vs lambda." }] }
];

export const deepLearningTopics: TopicContent[] = [
  { title: "Perceptrons & MLPs", theory: "A perceptron is the simplest neural unit: weighted sum of inputs + bias passed through an activation function. Multi-Layer Perceptrons (MLPs) stack layers of perceptrons to learn non-linear functions.\n\nArchitecture: input layer → hidden layers → output layer. Each neuron: z = Wx + b, a = activation(z). Universal Approximation Theorem: a single hidden layer MLP can approximate any continuous function (given enough neurons). Common activations: sigmoid, tanh, ReLU. MLPs are fully connected (dense) networks.", keyPoints: ["Perceptron: z = Σ(wᵢxᵢ) + b, output = activation(z)", "MLP: multiple layers of perceptrons", "Universal Approximation Theorem", "Activation functions introduce non-linearity", "Fully connected: every neuron connects to all in next layer"], codeExample: { language: "python", code: `import numpy as np\n\nclass MLP:\n    def __init__(self, layers):\n        self.weights = []\n        self.biases = []\n        for i in range(len(layers)-1):\n            w = np.random.randn(layers[i], layers[i+1]) * 0.1\n            b = np.zeros((1, layers[i+1]))\n            self.weights.append(w)\n            self.biases.append(b)\n    \n    def relu(self, z): return np.maximum(0, z)\n    def sigmoid(self, z): return 1 / (1 + np.exp(-z))\n    \n    def forward(self, X):\n        self.activations = [X]\n        for i, (w, b) in enumerate(zip(self.weights, self.biases)):\n            z = self.activations[-1] @ w + b\n            a = self.sigmoid(z) if i == len(self.weights)-1 else self.relu(z)\n            self.activations.append(a)\n        return self.activations[-1]\n\nmlp = MLP([4, 8, 4, 1])  # 4 inputs, 2 hidden layers, 1 output\nout = mlp.forward(np.random.randn(1, 4))\nprint(f"Output: {out}")`, explanation: "MLP from scratch with ReLU hidden layers and sigmoid output — forward pass demonstration." }, handsOn: [{ task: "Build an MLP from scratch and train it on XOR problem using backpropagation.", hint: "XOR requires at least one hidden layer. Use gradient descent with chain rule." }, { task: "Experiment with different activation functions and observe their effect on training.", hint: "Compare sigmoid, tanh, ReLU on same data; plot loss curves." }] },
  { title: "Backpropagation", theory: "Backpropagation computes gradients of the loss function with respect to each weight by applying the chain rule of calculus layer by layer, from output to input.\n\nForward pass: compute predictions. Loss: measure prediction error. Backward pass: compute gradients using chain rule (∂L/∂w = ∂L/∂a · ∂a/∂z · ∂z/∂w). Update: w = w - lr · ∂L/∂w. Computational graphs make backprop systematic. Vanishing gradients (sigmoid) and exploding gradients are common issues.", keyPoints: ["Chain rule: ∂L/∂w = ∂L/∂a × ∂a/∂z × ∂z/∂w", "Forward pass computes outputs; backward pass computes gradients", "Learning rate controls step size", "Vanishing gradients: sigmoid/tanh squash gradients", "Gradient clipping prevents exploding gradients"], handsOn: [{ task: "Implement backpropagation for a 2-layer neural network from scratch.", hint: "Compute output error, propagate back: dW2 = hidden.T @ d_output, dW1 = input.T @ d_hidden." }, { task: "Visualize gradient flow through layers and identify vanishing gradient problem.", hint: "Print gradient magnitudes at each layer during training; compare sigmoid vs ReLU." }] },
  { title: "CNNs", theory: "Convolutional Neural Networks are designed for spatial data (images). Convolutional layers apply learnable filters that detect features (edges, textures, objects). Pooling layers reduce spatial dimensions.\n\nArchitecture: Conv → ReLU → Pool → ... → Flatten → Dense → Output. Key concepts: filters/kernels, stride, padding, feature maps. Max pooling takes the maximum value in each window. Transfer learning: use pre-trained CNNs (ResNet, VGG) as feature extractors. CNNs exploit spatial locality and translation invariance.", keyPoints: ["Convolution: slide filter across input, compute dot products", "Pooling: reduce dimensions (max pooling most common)", "Feature maps: output of convolutional layer", "Parameter sharing: same filter across entire input", "Transfer learning: reuse pre-trained CNN features"], handsOn: [{ task: "Build a CNN for MNIST digit classification using a deep learning framework.", hint: "Conv2D(32, 3×3) → ReLU → MaxPool → Conv2D(64, 3×3) → ReLU → MaxPool → Dense → Softmax." }, { task: "Visualize convolutional filters and feature maps at different layers.", hint: "Extract weights from conv layers; plot as images. Feed an image and display intermediate outputs." }] },
  { title: "RNNs & LSTMs", theory: "Recurrent Neural Networks process sequential data by maintaining a hidden state that captures temporal information. At each timestep: h_t = f(W_h · h_{t-1} + W_x · x_t + b).\n\nVanilla RNNs suffer from vanishing/exploding gradients for long sequences. LSTMs (Long Short-Term Memory) solve this with gates: forget gate (what to discard), input gate (what to store), output gate (what to output). GRUs (Gated Recurrent Units) simplify LSTMs with fewer parameters. Bidirectional RNNs process sequences in both directions.", keyPoints: ["RNN: hidden state carries information across timesteps", "Vanishing gradients limit vanilla RNN to short sequences", "LSTM: forget, input, output gates control memory", "GRU: simplified LSTM with reset and update gates", "Bidirectional: process forward and backward for richer context"], handsOn: [{ task: "Build an LSTM network for text generation character by character.", hint: "Train on text corpus; at each step, predict next character given sequence of previous characters." }, { task: "Compare RNN, LSTM, and GRU on a sentiment analysis task.", hint: "Embed words → sequence model → dense → sigmoid. Compare accuracy and training speed." }] },
  { title: "GANs", theory: "Generative Adversarial Networks consist of two neural networks competing: a Generator creates fake data, and a Discriminator distinguishes real from fake. Training is a minimax game: G minimizes, D maximizes the discrimination objective.\n\nTraining dynamics: D gets better at detecting fakes → G gets better at creating realistic fakes → equilibrium. Mode collapse: G generates limited variety. Variants: DCGAN (convolutional), WGAN (Wasserstein distance), StyleGAN (high-quality faces), CycleGAN (unpaired image translation). Applications: image generation, super-resolution, data augmentation.", keyPoints: ["Generator: random noise → realistic data", "Discriminator: real vs fake classification", "Minimax game: G and D compete and improve", "Mode collapse: generator lacks diversity", "Applications: image synthesis, style transfer, data augmentation"], handsOn: [{ task: "Implement a simple GAN to generate handwritten digits (MNIST).", hint: "Generator: noise → Dense → reshape → Conv2DTranspose. Discriminator: Conv2D → Dense → sigmoid." }, { task: "Experiment with training stability: learning rates, label smoothing, batch normalization.", hint: "Label smoothing: use 0.9 instead of 1.0 for real labels. BN stabilizes training." }] },
  { title: "Autoencoders", theory: "Autoencoders learn compressed representations by training to reconstruct their input. Architecture: Encoder (compress) → Bottleneck (latent space) → Decoder (reconstruct). The bottleneck forces learning of essential features.\n\nVariants: Sparse (sparsity constraint on activations), Denoising (reconstruct from corrupted input), Variational (VAE — learns a distribution, enables generation). VAEs model latent space as a probability distribution, enabling smooth interpolation and generation. Applications: dimensionality reduction, anomaly detection, denoising, generation.", keyPoints: ["Encoder compresses; Decoder reconstructs", "Bottleneck forces learning essential features", "VAE: latent space is a probability distribution", "Denoising AE: trained to remove noise", "Applications: compression, anomaly detection, generation"], handsOn: [{ task: "Build a denoising autoencoder for image denoising on MNIST.", hint: "Add Gaussian noise to images; train AE to reconstruct clean images from noisy ones." }, { task: "Implement a Variational Autoencoder and generate new images by sampling the latent space.", hint: "Encoder outputs μ and σ; sample z = μ + σ×ε; decoder generates from z." }] },
  { title: "Transfer Learning", theory: "Transfer learning reuses a model trained on a large dataset (source) for a different task (target). Instead of training from scratch, you leverage learned features. This is especially powerful when target data is limited.\n\nStrategies: Feature extraction (freeze pre-trained layers, add new classifier), Fine-tuning (unfreeze some layers, train with low learning rate). Popular pre-trained models: ResNet, VGG, EfficientNet (images), BERT, GPT (text). The lower layers learn general features (edges, textures); higher layers learn task-specific features.", keyPoints: ["Reuse knowledge from large pre-trained models", "Feature extraction: freeze base, train only new head", "Fine-tuning: unfreeze top layers with low learning rate", "Lower layers: general features; Higher layers: specific features", "Enables good performance with limited data"], handsOn: [{ task: "Use a pre-trained ResNet for a custom image classification task with fine-tuning.", hint: "Load ResNet50, freeze all but last few layers, replace final dense layer, train on your data." }, { task: "Compare training from scratch vs transfer learning on a small dataset (100 images/class).", hint: "Train both approaches; measure accuracy, convergence speed, and overfitting." }] },
  { title: "Regularization", theory: "Regularization prevents overfitting by adding constraints or noise during training. L1/L2 regularization adds penalty terms to the loss function. Dropout randomly deactivates neurons during training, forcing redundancy.\n\nBatch Normalization normalizes layer inputs, stabilizing and accelerating training. Data augmentation artificially expands the training set (flip, rotate, crop, color jitter). Early stopping monitors validation loss and stops when it starts increasing. Ensemble methods (dropout at inference = MC Dropout) also regularize.", keyPoints: ["L2 (weight decay): penalizes large weights", "Dropout: randomly zero neurons during training", "Batch Normalization: normalize layer inputs", "Data augmentation: artificially expand training data", "Early stopping: halt when validation loss increases"], handsOn: [{ task: "Train a model with and without dropout, comparing training vs validation curves.", hint: "With dropout: smaller gap between train/val accuracy (less overfitting)." }, { task: "Implement data augmentation for an image classifier and measure improvement.", hint: "Apply random: horizontal flip, rotation ±15°, zoom ±10%, brightness variation." }] },
  { title: "Optimizers", theory: "Optimizers determine how model parameters are updated during training. SGD (Stochastic Gradient Descent) updates using a subset of data. Momentum accelerates SGD by accumulating past gradients.\n\nAdaptive methods adjust learning rates per-parameter: AdaGrad (accumulates squared gradients, decreasing lr), RMSprop (exponential moving average of squared gradients), Adam (combines momentum + RMSprop, most popular). Learning rate scheduling: step decay, cosine annealing, warmup. Adam with weight decay (AdamW) is current best practice.", keyPoints: ["SGD + Momentum: accelerates convergence", "Adam: adaptive learning rates, most widely used", "Learning rate is the most important hyperparameter", "Learning rate scheduling improves convergence", "AdamW: Adam with decoupled weight decay"], handsOn: [{ task: "Compare SGD, SGD+Momentum, and Adam on the same model and dataset.", hint: "Track loss curves for each; Adam typically converges faster initially." }, { task: "Implement a learning rate scheduler (cosine annealing) and observe its effect.", hint: "lr = min_lr + 0.5 * (max_lr - min_lr) * (1 + cos(π * epoch / total_epochs))." }] },
  { title: "Batch Normalization", theory: "Batch Normalization normalizes the inputs to each layer by subtracting the batch mean and dividing by batch standard deviation. It then scales and shifts using learnable parameters γ and β.\n\nBenefits: faster training (allows higher learning rates), reduces sensitivity to initialization, acts as a mild regularizer. Applied after linear transformation, before activation. During inference, uses running statistics (exponential moving average) instead of batch statistics. Layer Normalization is an alternative for variable-length sequences (RNNs/Transformers).", keyPoints: ["Normalize: x̂ = (x - μ_batch) / √(σ²_batch + ε)", "Scale and shift: y = γx̂ + β (learnable)", "Enables higher learning rates", "Uses running statistics at inference time", "Layer Norm: alternative for sequence models"], handsOn: [{ task: "Train the same network with and without BatchNorm; compare convergence speed.", hint: "Add BatchNorm after each dense/conv layer before activation. Compare loss curves." }, { task: "Implement BatchNorm from scratch — forward and backward pass.", hint: "Forward: compute mean, var, normalize, scale, shift. Backward: chain rule through all operations." }] }
];

export const dataScienceTopics: TopicContent[] = [
  { title: "Data Wrangling", theory: "Data wrangling transforms raw data into a clean, structured format suitable for analysis. It involves handling missing values, removing duplicates, correcting data types, and reshaping data.\n\nMissing data strategies: drop rows/columns, fill with mean/median/mode, interpolation, or use ML-based imputation. Outlier detection: IQR method, Z-score, visual inspection. Data type conversion ensures proper operations. Reshaping: pivot (long to wide), melt (wide to long), merge/join datasets.", keyPoints: ["Missing values: drop, fill (mean/median/mode), or impute", "Outlier detection: IQR (Q1-1.5×IQR to Q3+1.5×IQR)", "Data types: ensure numeric, categorical, datetime are correct", "Merge/join: combine datasets on common keys", "Pandas: primary Python tool for data wrangling"], handsOn: [{ task: "Clean a messy dataset: handle missing values, fix data types, remove duplicates.", hint: "Use df.isnull().sum(), df.fillna(), df.astype(), df.drop_duplicates()." }, { task: "Merge two datasets on a common key and handle mismatches.", hint: "Use pd.merge() with how='left/right/inner/outer' based on requirements." }] },
  { title: "Exploratory Data Analysis", theory: "EDA is the process of analyzing datasets to summarize their main characteristics using statistical summaries and visualizations. It helps understand data distribution, relationships, and patterns before modeling.\n\nKey techniques: descriptive statistics (mean, median, mode, std), distribution analysis (histograms, box plots), correlation analysis (heatmaps, scatter plots), group comparisons. EDA guides feature engineering, model selection, and identifies data quality issues.", keyPoints: ["Descriptive stats: mean, median, mode, std, percentiles", "Distribution: histograms, KDE plots, box plots", "Correlation: Pearson (linear), Spearman (monotonic)", "Visualization: matplotlib, seaborn, plotly", "EDA drives feature engineering and model selection"], handsOn: [{ task: "Perform complete EDA on a dataset: distributions, correlations, group comparisons.", hint: "Use df.describe(), df.corr(), sns.heatmap(), sns.pairplot(), group by and compare." }, { task: "Create an interactive EDA dashboard with multiple linked visualizations.", hint: "Use plotly/dash or streamlit with filters for dynamic exploration." }] },
  { title: "Statistical Testing", theory: "Statistical tests determine whether observed differences are statistically significant or due to random chance. Hypothesis testing: null hypothesis (H₀: no effect), alternative hypothesis (H₁: there is an effect).\n\nCommon tests: t-test (compare means), chi-square (categorical associations), ANOVA (compare multiple groups), Mann-Whitney (non-parametric). P-value: probability of observing results if H₀ is true. α = 0.05 is common significance level. Type I error: false positive. Type II error: false negative.", keyPoints: ["p-value < α → reject null hypothesis", "t-test: compare means of two groups", "Chi-square: test independence of categorical variables", "ANOVA: compare means across multiple groups", "Confidence interval: range of plausible values for parameter"], handsOn: [{ task: "Conduct a t-test to compare average scores between two groups.", hint: "scipy.stats.ttest_ind(group1, group2); check p-value against α=0.05." }, { task: "Perform a chi-square test to check if two categorical variables are independent.", hint: "Create contingency table with pd.crosstab(); use chi2_contingency()." }] },
  { title: "Data Visualization", theory: "Data visualization communicates insights through graphical representations. The choice of chart depends on the data type and message: comparison (bar), distribution (histogram, box plot), relationship (scatter), composition (pie, stacked bar), trend (line).\n\nPrinciples: data-ink ratio (minimize non-data ink), avoid chart junk, use appropriate scales, color meaningfully. Tools: Matplotlib (flexible), Seaborn (statistical), Plotly (interactive), D3.js (web). Storytelling with data: guide the audience through insights.", keyPoints: ["Choose chart type based on data and message", "Matplotlib: flexible, low-level control", "Seaborn: statistical visualizations with Pandas", "Plotly: interactive, web-ready charts", "Principles: clarity, accuracy, appropriate encoding"], handsOn: [{ task: "Create a comprehensive visualization report with 5+ different chart types.", hint: "Include: histogram, scatter, box plot, heatmap, line chart. Use subplots for layout." }, { task: "Build an interactive dashboard that allows filtering and drill-down.", hint: "Use Plotly Dash or Streamlit with dropdown filters and linked charts." }] },
  { title: "Feature Engineering", theory: "Feature engineering creates new features from raw data to improve model performance. It's often the most impactful step in the ML pipeline. Good features capture domain knowledge and make patterns easier for models to learn.\n\nTechniques: polynomial features, interaction terms, binning, log/power transforms, encoding categoricals (one-hot, label, target), datetime features (day of week, month, holidays), text features (TF-IDF, word counts), aggregation features (mean, sum, count by group).", keyPoints: ["Feature creation is often more impactful than model selection", "One-hot encoding for nominal categories", "Target encoding for high-cardinality features", "Polynomial features capture non-linear relationships", "Feature selection: filter, wrapper, embedded methods"], handsOn: [{ task: "Engineer features from a raw dataset and measure their impact on model performance.", hint: "Create interaction terms, binned features, encodings. Compare model accuracy before/after." }, { task: "Implement target encoding with proper cross-validation to avoid data leakage.", hint: "Compute target mean per category using only training folds; apply to validation fold." }] },
  { title: "Pandas & NumPy", theory: "Pandas provides high-level data structures (DataFrame, Series) for data manipulation. NumPy provides efficient multi-dimensional array operations. Together, they form the foundation of Python data science.\n\nPandas: read_csv, filtering, groupby, merge, pivot_table, apply, rolling windows. NumPy: vectorized operations, broadcasting, linear algebra, random number generation. Vectorized operations are 10-100x faster than Python loops. Memory efficiency: use appropriate dtypes (int8 vs int64, category).", keyPoints: ["DataFrame: 2D labeled data structure (like a spreadsheet)", "Vectorized operations: avoid loops, use array operations", "GroupBy: split-apply-combine pattern", "Broadcasting: operations between arrays of different shapes", "Memory: use category dtype for repeated strings"], codeExample: { language: "python", code: `import pandas as pd\nimport numpy as np\n\n# Efficient data analysis pipeline\ndf = pd.DataFrame({\n    'date': pd.date_range('2024-01-01', periods=1000),\n    'category': np.random.choice(['A', 'B', 'C'], 1000),\n    'value': np.random.randn(1000) * 100 + 500\n})\n\n# Chain operations (vectorized, fast)\nresult = (\n    df\n    .assign(month=lambda x: x['date'].dt.month)\n    .groupby(['category', 'month'])\n    .agg(avg_value=('value', 'mean'),\n         total=('value', 'sum'),\n         count=('value', 'count'))\n    .reset_index()\n    .sort_values('avg_value', ascending=False)\n)\nprint(result.head())`, explanation: "Pandas method chaining for efficient data transformation — groupby, aggregate, sort in one pipeline." }, handsOn: [{ task: "Solve 5 data manipulation challenges using only Pandas (no loops).", hint: "Filter, groupby, merge, pivot, and window functions cover most needs." }, { task: "Optimize a slow data processing pipeline by replacing loops with vectorized NumPy operations.", hint: "Profile first; replace iterrows() with vectorized operations; use .values for NumPy arrays." }] },
  { title: "SQL for Data Science", theory: "SQL is essential for extracting and transforming data from relational databases. Data scientists use SQL for data extraction, exploration, and creating datasets for analysis.\n\nKey patterns: JOIN (combine tables), GROUP BY + aggregates (summarize), window functions (running totals, ranks), CTEs (readable subqueries), CASE statements (conditional logic). Performance: use indexes, avoid SELECT *, filter early with WHERE. Modern tools: dbt for SQL transformations, SQL notebooks for analysis.", keyPoints: ["JOIN: INNER, LEFT, RIGHT, FULL for combining tables", "Window functions: RANK, LAG, LEAD, running sums", "CTE: readable, reusable subquery with WITH clause", "GROUP BY + HAVING for aggregation and filtering", "Index-aware queries for performance"], codeExample: { language: "sql", code: `-- Customer lifetime value analysis\nWITH customer_orders AS (\n    SELECT \n        c.customer_id,\n        c.name,\n        COUNT(o.order_id) as total_orders,\n        SUM(o.amount) as total_spent,\n        MIN(o.order_date) as first_order,\n        MAX(o.order_date) as last_order,\n        AVG(o.amount) as avg_order_value\n    FROM customers c\n    LEFT JOIN orders o ON c.customer_id = o.customer_id\n    GROUP BY c.customer_id, c.name\n)\nSELECT *,\n    NTILE(4) OVER (ORDER BY total_spent DESC) as spending_quartile,\n    DATEDIFF(last_order, first_order) as customer_lifespan_days\nFROM customer_orders\nORDER BY total_spent DESC;`, explanation: "Customer analytics query with CTE, aggregation, and window functions — common data science SQL pattern." }, handsOn: [{ task: "Write SQL queries for cohort analysis: group users by signup month, track retention.", hint: "CTE to assign cohort; LEFT JOIN activities; count distinct users per cohort per month." }, { task: "Optimize a slow query using EXPLAIN ANALYZE and add appropriate indexes.", hint: "Check for full table scans; add indexes on JOIN and WHERE columns." }] },
  { title: "A/B Testing", theory: "A/B testing compares two versions (control A vs treatment B) to determine which performs better. It's the gold standard for making data-driven decisions in product development.\n\nProcess: define hypothesis → determine sample size (power analysis) → randomize users → collect data → analyze results. Statistical significance: is the difference real or due to chance? Effect size: is the difference meaningful? Common pitfalls: peeking at results early, multiple testing, selection bias, novelty effects.", keyPoints: ["Control group (A) vs treatment group (B)", "Power analysis determines required sample size", "p-value < 0.05: statistically significant result", "Effect size: practical significance (not just statistical)", "Common pitfalls: peeking, multiple testing, selection bias"], handsOn: [{ task: "Design and simulate an A/B test for a website change.", hint: "Generate data with known effect; run t-test; check if you correctly detect the difference." }, { task: "Perform power analysis to determine the sample size for a planned A/B test.", hint: "Use statsmodels.stats.power: specify effect size, alpha, power (0.8); compute sample size." }] },
  { title: "Dashboarding", theory: "Dashboards provide interactive visual summaries of key metrics and KPIs. They enable stakeholders to monitor performance, identify trends, and make data-driven decisions.\n\nDesign principles: identify the audience and their questions, choose relevant KPIs, use appropriate visualizations, minimize clutter, enable drill-down. Tools: Tableau, Power BI, Metabase (BI tools), Streamlit, Dash (Python frameworks), Grafana (monitoring). Real-time dashboards update automatically; static dashboards are refreshed periodically.", keyPoints: ["KPIs: Key Performance Indicators relevant to the audience", "Above the fold: most important metrics visible without scrolling", "Drill-down: overview → details on demand", "Tools: Tableau, Power BI (business), Streamlit, Dash (Python)", "Real-time vs periodic refresh based on needs"], handsOn: [{ task: "Build a sales dashboard with KPIs, trends, and drill-down capabilities.", hint: "Use Streamlit or Dash; include revenue, orders, top products, time series trend." }, { task: "Create a monitoring dashboard that auto-refreshes with live data.", hint: "Use Streamlit with st.experimental_rerun() or Grafana with a data source." }] }
];

export const nlpTopics: TopicContent[] = [
  { title: "Tokenization", theory: "Tokenization splits text into smaller units (tokens) — words, subwords, or characters. It's the first step in NLP pipelines. Different languages and applications require different tokenization strategies.\n\nWord tokenization: split by spaces/punctuation. Subword tokenization (BPE, WordPiece, SentencePiece): handles unknown words by breaking them into known subword units. Character tokenization: finest granularity. Modern LLMs use subword tokenizers (GPT uses BPE, BERT uses WordPiece). Tokenizer training learns the vocabulary from data.", keyPoints: ["Word tokenization: simple but large vocabulary, OOV problems", "BPE (Byte Pair Encoding): iteratively merge frequent character pairs", "WordPiece: similar to BPE, used by BERT", "SentencePiece: language-agnostic, works on raw text", "Vocabulary size tradeoff: too small = long sequences, too large = sparse embeddings"], handsOn: [{ task: "Implement a simple BPE tokenizer from scratch.", hint: "Start with character-level; find most frequent pair; merge; repeat until vocab size reached." }, { task: "Compare word, BPE, and character tokenization on a multilingual dataset.", hint: "Measure: vocabulary size, average tokens per sentence, OOV rate." }] },
  { title: "Word Embeddings", theory: "Word embeddings represent words as dense vectors in continuous space, capturing semantic relationships. Similar words have similar vectors. Word2Vec, GloVe, and FastText are foundational embedding methods.\n\nWord2Vec: Skip-gram (predict context from word) and CBOW (predict word from context). GloVe: learns from global word co-occurrence statistics. FastText: uses character n-grams, handles unseen words. Embeddings capture analogies: king - man + woman ≈ queen. Pre-trained embeddings transfer knowledge.", keyPoints: ["Dense vectors capture semantic meaning", "Word2Vec: Skip-gram and CBOW models", "GloVe: global co-occurrence matrix factorization", "FastText: character n-grams handle OOV words", "Analogy: king - man + woman ≈ queen"], handsOn: [{ task: "Train Word2Vec embeddings on a text corpus and explore word analogies.", hint: "Use gensim: Word2Vec(sentences, vector_size=100). Test: model.most_similar(positive=['king','woman'], negative=['man'])." }, { task: "Visualize word embeddings in 2D using t-SNE and identify clusters.", hint: "Reduce dimensions with t-SNE; plot words as points; similar words should cluster." }] },
  { title: "Seq2Seq Models", theory: "Sequence-to-sequence models map variable-length input sequences to variable-length output sequences. Architecture: Encoder processes input → context vector → Decoder generates output one token at a time.\n\nApplications: machine translation, summarization, question answering. The encoder's final hidden state becomes the initial state for the decoder. Teacher forcing: feed ground truth (not prediction) as decoder input during training. Limitation: fixed-size context vector is a bottleneck for long sequences — solved by attention mechanism.", keyPoints: ["Encoder-Decoder architecture", "Encoder compresses input into context vector", "Decoder generates output token by token", "Teacher forcing improves training stability", "Bottleneck: fixed context vector limits long sequence handling"], handsOn: [{ task: "Build a simple Seq2Seq model for date format conversion (e.g., 'January 5, 2024' → '2024-01-05').", hint: "Character-level encoder-decoder; train on pairs of date formats." }, { task: "Implement teacher forcing and compare training with and without it.", hint: "With: feed ground truth to decoder. Without: feed decoder's own prediction. Compare convergence." }] },
  { title: "Attention Mechanism", theory: "Attention allows the model to focus on relevant parts of the input when generating each output token. Instead of compressing everything into a fixed vector, it creates a weighted combination of all encoder states.\n\nScaled dot-product attention: score = Q·K^T / √d_k, weights = softmax(score), output = weights·V. Self-attention: Q, K, V all come from the same sequence. Multi-head attention runs multiple attention in parallel, each learning different relationships. Attention is the core of Transformers.", keyPoints: ["Attention weight = how relevant each input token is", "Scaled dot-product: Attention(Q,K,V) = softmax(QK^T/√d)V", "Self-attention: attend to other positions in same sequence", "Multi-head: multiple attention functions in parallel", "Solves the bottleneck problem of fixed-size context"], handsOn: [{ task: "Implement scaled dot-product attention from scratch and visualize attention weights.", hint: "Compute QK^T, scale by √d_k, softmax for weights, multiply by V. Heatmap for visualization." }, { task: "Add attention to a Seq2Seq model and compare performance with/without.", hint: "At each decoder step, compute attention over all encoder hidden states." }] },
  { title: "Transformers", theory: "Transformers replaced RNNs by processing entire sequences in parallel using self-attention. Architecture: Multi-Head Self-Attention → Add & Norm → Feed-Forward → Add & Norm, stacked N times.\n\nPositional encoding adds sequence order information since attention is permutation-invariant. Encoder-only (BERT): bidirectional, good for classification. Decoder-only (GPT): autoregressive, good for generation. Encoder-Decoder (T5, BART): good for translation/summarization. Transformers scale well with data and compute.", keyPoints: ["Self-attention enables parallel processing of sequences", "Positional encoding provides order information", "Multi-head attention captures different relationship types", "Layer normalization + residual connections enable deep networks", "Scales better than RNNs with data and compute"], handsOn: [{ task: "Implement a minimal Transformer encoder block from scratch.", hint: "Multi-head attention → residual + layer norm → FFN → residual + layer norm." }, { task: "Fine-tune a pre-trained Transformer (BERT) for text classification.", hint: "Load pre-trained model, add classification head, fine-tune with low learning rate." }] },
  { title: "BERT & GPT", theory: "BERT (Bidirectional Encoder Representations from Transformers) is pre-trained with masked language modeling and next sentence prediction. It sees context from both directions, making it excellent for understanding tasks.\n\nGPT (Generative Pre-trained Transformer) is decoder-only, trained autoregressively (predict next token). GPT excels at text generation. BERT → fine-tune for classification, NER, QA. GPT → few-shot/zero-shot via prompting. Both use transfer learning: pre-train on large corpus, fine-tune/prompt for specific tasks.", keyPoints: ["BERT: bidirectional, masked language modeling", "GPT: autoregressive, left-to-right generation", "BERT: best for understanding (classification, NER, QA)", "GPT: best for generation (text, code, conversation)", "Both: pre-train on large corpus → fine-tune/prompt"], handsOn: [{ task: "Fine-tune BERT for sentiment analysis on movie reviews.", hint: "Use HuggingFace: BertForSequenceClassification. Tokenize, create DataLoader, train with AdamW." }, { task: "Use GPT for zero-shot classification via prompting.", hint: "Prompt: 'Classify this text as positive or negative: [text]. Answer:'" }] },
  { title: "Sentiment Analysis", theory: "Sentiment analysis determines the emotional tone of text: positive, negative, or neutral. It's one of the most common NLP applications, used for product reviews, social media monitoring, and customer feedback.\n\nApproaches: Rule-based (lexicon with sentiment scores), Traditional ML (TF-IDF + SVM/Naive Bayes), Deep Learning (LSTM, CNN on word embeddings), Transformers (fine-tuned BERT). Challenges: sarcasm, negation ('not bad'), context-dependent sentiment, domain-specific language.", keyPoints: ["Lexicon-based: dictionary of word sentiments", "ML approach: TF-IDF features + classifier", "Deep learning: embeddings + LSTM/CNN", "BERT: state-of-the-art with fine-tuning", "Challenges: sarcasm, negation, domain specificity"], handsOn: [{ task: "Build a sentiment classifier using TF-IDF + Logistic Regression.", hint: "TfidfVectorizer to extract features; LogisticRegression for classification; evaluate with F1." }, { task: "Fine-tune a pre-trained BERT model for domain-specific sentiment analysis.", hint: "Use HuggingFace pipeline; fine-tune on your domain data for better accuracy." }] },
  { title: "Named Entity Recognition", theory: "Named Entity Recognition (NER) identifies and classifies named entities in text: persons, organizations, locations, dates, monetary values, etc. It's a sequence labeling task.\n\nApproaches: Rule-based (regex, gazetteers), CRF (Conditional Random Fields), BiLSTM-CRF (deep learning + CRF layer), Transformer-based (BERT + token classification). IOB tagging: B-PER (begin person), I-PER (inside person), O (outside). SpaCy provides pre-trained NER models for quick usage.", keyPoints: ["IOB tagging: B (begin), I (inside), O (outside entity)", "CRF: probabilistic sequence model for structured prediction", "BiLSTM-CRF: deep features + structured output", "BERT NER: token classification fine-tuning", "SpaCy: production-ready NER out of the box"], handsOn: [{ task: "Train a NER model using SpaCy on custom entity types.", hint: "Define training data with entity spans; use spacy.blank('en') and train the ner component." }, { task: "Fine-tune BERT for NER using HuggingFace token classification.", hint: "Use BertForTokenClassification; align tokenization with IOB labels; train with cross-entropy." }] },
  { title: "Text Classification", theory: "Text classification assigns predefined labels to text documents. Applications: spam detection, topic categorization, intent recognition, language detection.\n\nPipeline: preprocess (lowercase, remove stopwords, lemmatize) → feature extraction (BoW, TF-IDF, embeddings) → classifier (Naive Bayes, SVM, neural network). Multi-class: each document gets one label. Multi-label: each document can have multiple labels. Evaluation: accuracy, precision, recall, F1 (macro/micro/weighted average).", keyPoints: ["Preprocessing: tokenize, lowercase, remove stopwords, lemmatize", "Feature extraction: Bag of Words, TF-IDF, word embeddings", "Naive Bayes: fast, good baseline for text", "Multi-class vs multi-label classification", "Evaluation: macro/micro F1 for imbalanced classes"], handsOn: [{ task: "Build a news article topic classifier using TF-IDF and SVM.", hint: "Use TfidfVectorizer + SVC with linear kernel; evaluate with classification_report." }, { task: "Implement a multi-label text classifier for tagging articles with multiple categories.", hint: "Use MultiLabelBinarizer for labels; OneVsRestClassifier wrapper for any classifier." }] },
  { title: "Language Generation", theory: "Language generation creates human-like text given a prompt or context. Autoregressive models (GPT) generate token by token, each conditioned on all previous tokens.\n\nDecoding strategies: Greedy (pick highest probability), Beam Search (explore top-k paths), Sampling (random from distribution), Top-k Sampling (sample from top k tokens), Nucleus/Top-p Sampling (sample from cumulative probability p). Temperature controls randomness: low = confident, high = creative. Evaluation: perplexity (lower = better), BLEU, ROUGE, human evaluation.", keyPoints: ["Autoregressive: generate one token at a time", "Greedy decoding: always pick most likely token", "Beam search: explore multiple hypotheses in parallel", "Top-p/Top-k sampling: controlled randomness", "Temperature: 0 = deterministic, 1+ = more creative"], handsOn: [{ task: "Implement text generation with different decoding strategies and compare outputs.", hint: "Use HuggingFace generate() with do_sample, top_k, top_p, temperature parameters." }, { task: "Fine-tune GPT-2 for domain-specific text generation (e.g., poetry, code, recipes).", hint: "Prepare domain text; fine-tune with HuggingFace Trainer; generate and evaluate." }] }
];

export const computerVisionTopics: TopicContent[] = [
  { title: "Image Processing", theory: "Image processing transforms images for analysis or enhancement. Images are 2D/3D arrays of pixel values. Color spaces: RGB, HSV, Grayscale, LAB. Operations: resizing, cropping, rotation, color conversion.\n\nFiltering: convolution with kernels for blurring (Gaussian), sharpening, edge detection (Sobel, Laplacian). Histogram equalization improves contrast. Morphological operations (erosion, dilation, opening, closing) process binary images. OpenCV is the primary library.", keyPoints: ["Images are NumPy arrays: (height, width, channels)", "Color spaces: RGB, HSV, Grayscale for different tasks", "Convolution: slide kernel over image for filtering", "Gaussian blur: noise reduction", "Histogram equalization: improve contrast"], handsOn: [{ task: "Apply Gaussian blur, edge detection (Sobel), and histogram equalization to an image.", hint: "Use cv2.GaussianBlur(), cv2.Sobel(), cv2.equalizeHist(). Display side by side." }, { task: "Implement a basic image filter (sharpen, emboss) using custom convolution kernels.", hint: "Sharpen kernel: [[0,-1,0],[-1,5,-1],[0,-1,0]]. Apply with cv2.filter2D()." }] },
  { title: "Edge Detection", theory: "Edge detection identifies boundaries in images where pixel intensity changes sharply. Edges correspond to object boundaries, texture changes, and depth discontinuities.\n\nGradient-based: Sobel (directional gradients), Prewitt. Laplacian: second derivative detects zero-crossings. Canny edge detector: the most popular algorithm. Canny steps: Gaussian blur → gradient computation → non-maximum suppression → double threshold → edge tracking by hysteresis.", keyPoints: ["Edges: significant changes in pixel intensity", "Sobel: detects horizontal and vertical edges separately", "Canny: most robust multi-stage edge detector", "Non-maximum suppression: thin edges to single pixel width", "Hysteresis thresholding: two thresholds for edge classification"], handsOn: [{ task: "Implement and compare Sobel, Laplacian, and Canny edge detection on the same image.", hint: "Use cv2.Sobel(), cv2.Laplacian(), cv2.Canny(). Compare quality and noise sensitivity." }, { task: "Tune Canny edge detector thresholds and observe their effect on detected edges.", hint: "Low threshold captures more edges (including noise); high threshold captures fewer, stronger edges." }] },
  { title: "Feature Extraction", theory: "Feature extraction identifies distinctive points or regions in images for tasks like matching, tracking, and recognition. Traditional methods extract hand-crafted features; deep learning extracts learned features.\n\nSIFT (Scale-Invariant Feature Transform): robust to scale and rotation. SURF: faster approximation of SIFT. ORB: open-source alternative. HOG (Histogram of Oriented Gradients): used for pedestrian detection. Feature matching: brute-force or FLANN-based. Deep features from CNN intermediate layers are now dominant.", keyPoints: ["SIFT: scale and rotation invariant keypoints", "ORB: fast, open-source feature detector", "HOG: gradient histogram for object detection", "Feature matching: find correspondences between images", "CNN features: learned, outperform hand-crafted for most tasks"], handsOn: [{ task: "Extract SIFT/ORB features from two images and match them.", hint: "Detect keypoints, compute descriptors, match with BFMatcher, filter by distance." }, { task: "Compute HOG features for an image and visualize the gradient orientations.", hint: "Use skimage.feature.hog() with visualize=True; overlay on original image." }] },
  { title: "Object Detection (YOLO, SSD)", theory: "Object detection locates and classifies objects in images with bounding boxes. Two-stage: R-CNN, Faster R-CNN (region proposal + classification). One-stage: YOLO (You Only Look Once), SSD (Single Shot Detector).\n\nYOLO divides the image into a grid; each cell predicts bounding boxes and class probabilities in one forward pass. SSD uses multi-scale feature maps. Evaluation: IoU (Intersection over Union), mAP (mean Average Precision). Non-Maximum Suppression (NMS) removes duplicate detections. YOLOv8 is the latest version.", keyPoints: ["YOLO: single forward pass, real-time detection", "SSD: multi-scale feature maps for different object sizes", "IoU: overlap between predicted and ground truth boxes", "mAP: mean Average Precision across classes", "NMS: remove overlapping duplicate detections"], handsOn: [{ task: "Run YOLOv8 on images/video and visualize detections with bounding boxes.", hint: "from ultralytics import YOLO; model = YOLO('yolov8n.pt'); results = model('image.jpg')." }, { task: "Calculate IoU between predicted and ground truth bounding boxes.", hint: "IoU = area_of_intersection / area_of_union. Handle edge cases where boxes don't overlap." }] },
  { title: "Image Segmentation", theory: "Image segmentation assigns a label to every pixel. Semantic segmentation: label each pixel with a class (all cars have same label). Instance segmentation: distinguish individual objects (each car has unique label). Panoptic: combines both.\n\nArchitectures: FCN (Fully Convolutional Network), U-Net (encoder-decoder with skip connections, popular in medical imaging), DeepLab (atrous convolution, CRF), Mask R-CNN (instance segmentation). Evaluation: pixel accuracy, mean IoU, Dice coefficient.", keyPoints: ["Semantic: per-pixel class labels", "Instance: distinguish individual objects", "U-Net: encoder-decoder with skip connections", "DeepLab: atrous/dilated convolutions for multi-scale", "Mask R-CNN: extends Faster R-CNN with mask branch"], handsOn: [{ task: "Train U-Net for binary image segmentation (e.g., foreground vs background).", hint: "Encoder: Conv+Pool stack. Decoder: UpConv + skip connections. Loss: binary cross-entropy + Dice." }, { task: "Evaluate segmentation results using IoU and Dice coefficient.", hint: "IoU = TP / (TP + FP + FN). Dice = 2×TP / (2×TP + FP + FN)." }] },
  { title: "Face Recognition", theory: "Face recognition identifies or verifies a person from their face. Pipeline: detection (find faces) → alignment (normalize pose) → encoding (extract features) → matching (compare encodings).\n\nDetection: Haar cascades (fast, old), MTCNN (multi-task CNN), RetinaFace. Recognition: FaceNet (triplet loss, 128-d embeddings), ArcFace (angular margin loss). Verification (1:1): is this person who they claim? Identification (1:N): who is this person? Challenges: lighting, pose, occlusion, aging.", keyPoints: ["Pipeline: detect → align → encode → match", "FaceNet: learns 128-d face embeddings with triplet loss", "Verification (1:1) vs Identification (1:N)", "Challenges: lighting, pose, occlusion, aging, bias", "Ethics: consent, bias, privacy considerations"], handsOn: [{ task: "Build a face detection system using OpenCV's Haar cascades or MTCNN.", hint: "Use cv2.CascadeClassifier or mtcnn library. Draw bounding boxes on detected faces." }, { task: "Create a simple face recognition system that identifies known people.", hint: "Use face_recognition library: encode known faces, compare with unknown using face_distance." }] },
  { title: "Optical Flow", theory: "Optical flow estimates the motion of pixels between consecutive video frames. It provides a dense motion field showing how each pixel moves.\n\nLucas-Kanade: sparse, tracks feature points (assumes small displacement). Farneback: dense, computes flow for every pixel. Horn-Schunck: global optimization with smoothness constraint. Deep learning: FlowNet, RAFT achieve state-of-the-art accuracy. Applications: video stabilization, action recognition, autonomous driving, video compression.", keyPoints: ["Optical flow: per-pixel motion vectors between frames", "Lucas-Kanade: sparse, fast, good for tracking features", "Farneback: dense, computes flow for all pixels", "Applications: tracking, action recognition, video analysis", "RAFT: deep learning method for accurate optical flow"], handsOn: [{ task: "Compute and visualize optical flow between two video frames using Farneback.", hint: "cv2.calcOpticalFlowFarneback(); visualize with HSV color coding (hue=direction, value=magnitude)." }, { task: "Track objects across video frames using Lucas-Kanade optical flow.", hint: "Detect features in first frame; track with cv2.calcOpticalFlowPyrLK(); draw tracks." }] },
  { title: "3D Vision", theory: "3D vision recovers 3D structure from 2D images. Stereo vision uses two cameras to estimate depth via triangulation. Depth estimation from a single image uses deep learning.\n\nKey concepts: camera calibration (intrinsic/extrinsic parameters), epipolar geometry, disparity maps, point clouds, Structure from Motion (SfM), Visual SLAM. Depth sensors: stereo cameras, structured light (Kinect), LiDAR, Time-of-Flight. Applications: autonomous driving, AR/VR, robotics, 3D reconstruction.", keyPoints: ["Stereo vision: depth from two camera views", "Disparity map: pixel displacement encodes depth", "Camera calibration: determine camera parameters", "Point cloud: 3D representation from depth data", "SfM: reconstruct 3D from multiple 2D images"], handsOn: [{ task: "Compute a disparity map from a stereo image pair.", hint: "Use cv2.StereoBM_create() or cv2.StereoSGBM_create(); tune numDisparities and blockSize." }, { task: "Calibrate a camera using a checkerboard pattern.", hint: "cv2.findChessboardCorners() → cv2.calibrateCamera() → get intrinsic matrix and distortion." }] },
  { title: "GANs for Images", theory: "GANs generate realistic images through adversarial training. Image-specific GAN architectures have pushed the boundaries of image synthesis, editing, and manipulation.\n\nDCGAN: convolutional architecture for stable training. StyleGAN: progressive growing + style mixing for high-quality faces. Pix2Pix: paired image-to-image translation (sketch → photo). CycleGAN: unpaired translation (horse ↔ zebra). Super-Resolution GANs (SRGAN, ESRGAN): upscale low-resolution images. Applications: art generation, face editing, data augmentation.", keyPoints: ["DCGAN: convolutional generator and discriminator", "StyleGAN: state-of-the-art face generation", "Pix2Pix: paired image-to-image translation", "CycleGAN: unpaired domain translation", "SRGAN: super-resolution image upscaling"], handsOn: [{ task: "Train a DCGAN to generate images from a custom dataset.", hint: "Generator: ConvTranspose2d layers. Discriminator: Conv2d layers. Train alternately." }, { task: "Use a pre-trained CycleGAN for style transfer between two image domains.", hint: "Load CycleGAN model; feed input image; get translated output." }] }
];

export const generativeAITopics: TopicContent[] = [
  { title: "LLM Architecture", theory: "Large Language Models are based on the Transformer architecture, specifically the decoder-only variant. They're trained on massive text corpora to predict the next token, learning language patterns, facts, and reasoning.\n\nKey components: token embeddings + positional encoding, multi-head self-attention with causal masking (can only attend to previous tokens), feed-forward networks, layer normalization. Scaling laws: performance improves predictably with model size, data, and compute. Key models: GPT-4, Claude, Gemini, LLaMA, Mistral.", keyPoints: ["Decoder-only Transformer with causal attention", "Pre-trained on massive text data (next token prediction)", "Scaling laws: bigger model + more data = better performance", "Context window: maximum sequence length", "Emergent abilities appear at scale"], handsOn: [{ task: "Explore LLM behavior by varying temperature, top-p, and max_tokens parameters.", hint: "Temperature 0 = deterministic; 1+ = creative. Top-p 0.1 = focused; 0.9 = diverse." }, { task: "Analyze tokenization of different models and understand token limits.", hint: "Use tiktoken library; compare token counts for same text across different models." }] },
  { title: "Prompt Engineering", theory: "Prompt engineering crafts effective inputs to get desired outputs from LLMs. It's the primary way to control LLM behavior without modifying model weights.\n\nTechniques: zero-shot (no examples), few-shot (provide examples), chain-of-thought (step-by-step reasoning), role prompting (assign persona), system prompts (set behavior context). Structured output: ask for JSON, markdown, specific formats. Prompt chaining: break complex tasks into sequential prompts. Negative prompting: specify what NOT to do.", keyPoints: ["Zero-shot: task description only", "Few-shot: provide examples of desired input-output pairs", "Chain-of-thought: 'Let's think step by step'", "System prompt: set role and behavior context", "Structured output: request specific format (JSON, markdown)"], handsOn: [{ task: "Compare zero-shot, few-shot, and chain-of-thought prompting on math word problems.", hint: "Same problems, different prompting strategies. Measure accuracy for each." }, { task: "Design a prompt template for consistent, structured code review feedback.", hint: "Include: summary, bugs found, style issues, suggestions, severity levels. Use examples." }] },
  { title: "Fine-Tuning", theory: "Fine-tuning adapts a pre-trained LLM to a specific task or domain by training on task-specific data. It modifies model weights to improve performance on the target use case.\n\nFull fine-tuning updates all parameters (expensive). Parameter-efficient methods: LoRA (Low-Rank Adaptation) adds small trainable matrices to frozen weights. QLoRA combines quantization with LoRA. RLHF (Reinforcement Learning from Human Feedback) aligns models with human preferences. Instruction tuning trains on (instruction, response) pairs.", keyPoints: ["Full fine-tuning: update all weights (resource-intensive)", "LoRA: add small trainable matrices, freeze base model", "QLoRA: 4-bit quantization + LoRA (fits on consumer GPUs)", "RLHF: align model behavior with human preferences", "Instruction tuning: train on instruction-response pairs"], handsOn: [{ task: "Fine-tune a small LLM using LoRA on a domain-specific dataset.", hint: "Use HuggingFace PEFT library; set r=8, alpha=16; train on your instruction dataset." }, { task: "Evaluate fine-tuned vs base model on domain-specific questions.", hint: "Compare: accuracy, hallucination rate, response quality on a held-out test set." }] },
  { title: "RAG Systems", theory: "Retrieval-Augmented Generation (RAG) enhances LLM responses with external knowledge. Instead of relying solely on training data, RAG retrieves relevant documents and includes them in the prompt.\n\nPipeline: User query → Embed query → Search vector database → Retrieve relevant chunks → Add to prompt context → Generate answer. Benefits: reduces hallucination, uses up-to-date information, domain-specific knowledge. Chunking strategies: fixed-size, sentence-based, semantic. Evaluation: faithfulness, relevance, answer correctness.", keyPoints: ["Retrieval + Generation: ground LLM responses in real data", "Vector database stores document embeddings", "Chunking: split documents into manageable pieces", "Embedding models: convert text to vectors for similarity search", "Reduces hallucination and enables domain knowledge"], handsOn: [{ task: "Build a simple RAG pipeline that answers questions from a PDF document.", hint: "Load PDF → chunk text → embed chunks → store in vector DB → query → retrieve → generate." }, { task: "Compare RAG answers vs vanilla LLM answers on domain-specific questions.", hint: "Ask same questions with and without retrieval; evaluate accuracy and hallucination." }] },
  { title: "Vector Databases", theory: "Vector databases store and efficiently search high-dimensional embedding vectors. They enable similarity search — finding the most similar items to a query vector — which is fundamental to RAG, recommendations, and semantic search.\n\nIndexing algorithms: Flat (exact, brute-force), IVF (inverted file index), HNSW (graph-based, best quality/speed tradeoff). Distance metrics: cosine similarity, Euclidean distance, dot product. Popular DBs: Pinecone, Weaviate, Chroma, Milvus, pgvector (PostgreSQL extension).", keyPoints: ["Store and search high-dimensional vectors efficiently", "HNSW: best tradeoff between search quality and speed", "Cosine similarity: most common for text embeddings", "Metadata filtering: combine vector search with attribute filters", "Popular: Pinecone (managed), Chroma (lightweight), pgvector (PostgreSQL)"], handsOn: [{ task: "Set up a vector database and perform semantic search on a document collection.", hint: "Use Chroma: embed documents, add to collection, query with natural language." }, { task: "Compare different distance metrics (cosine, euclidean, dot product) on search quality.", hint: "Same queries, same data; compare top-5 results and relevance scores for each metric." }] },
  { title: "AI Agents", theory: "AI agents are LLM-powered systems that can reason, plan, and take actions using tools. Unlike simple chatbots, agents can break down complex tasks, use APIs, search the web, write code, and interact with external systems.\n\nArchitecture: LLM (brain) + Tools (actions) + Memory (context). ReAct pattern: Reason → Act → Observe → repeat. Tool use: function calling, API integration. Planning: task decomposition, self-reflection. Frameworks: LangChain, AutoGen, CrewAI. Multi-agent systems have multiple agents collaborating.", keyPoints: ["Agent = LLM + Tools + Memory + Planning", "ReAct: Reason-Act-Observe loop", "Tool use: LLM calls functions/APIs as needed", "Memory: short-term (conversation) + long-term (vector DB)", "Frameworks: LangChain, AutoGen for building agents"], handsOn: [{ task: "Build a simple AI agent that can search the web and answer questions.", hint: "Define tools (search, calculator); use ReAct loop: think → choose tool → observe result → answer." }, { task: "Create a multi-agent system where agents collaborate to solve a complex task.", hint: "Define roles (researcher, writer, reviewer); agents pass work to each other." }] },
  { title: "Multimodal Models", theory: "Multimodal models process and generate multiple data types: text, images, audio, video. They can understand images and respond in text, generate images from text descriptions, or combine information across modalities.\n\nArchitectures: CLIP (contrastive learning between images and text), DALL-E/Midjourney (text-to-image), GPT-4V/Gemini (vision + language), Whisper (audio-to-text). Vision-Language models encode images and text into a shared embedding space. Applications: visual QA, image captioning, document understanding.", keyPoints: ["Process multiple data types: text, images, audio, video", "CLIP: shared embedding space for images and text", "Vision-Language models: understand and describe images", "Text-to-image: DALL-E, Stable Diffusion, Midjourney", "Applications: VQA, captioning, document understanding"], handsOn: [{ task: "Use a vision-language model to analyze and describe images.", hint: "Use GPT-4V or Gemini API; send image with prompt 'Describe this image in detail'." }, { task: "Build an image search engine using CLIP embeddings.", hint: "Encode images and text queries with CLIP; find images with highest cosine similarity to query text." }] },
  { title: "Ethics in AI", theory: "AI ethics addresses the responsible development and deployment of AI systems. Key concerns: bias (training data reflects societal biases), fairness (equal treatment across groups), privacy (data collection and usage), transparency (explainability of decisions).\n\nBias types: historical (past discrimination in data), representation (underrepresentation of groups), measurement (proxies for protected attributes). Mitigation: diverse training data, fairness constraints, bias auditing, human oversight. Regulations: EU AI Act, NIST AI Framework. Responsible AI: safety, reliability, inclusivity, accountability.", keyPoints: ["Bias: AI can amplify societal biases in training data", "Fairness: equal treatment across demographic groups", "Transparency: explain how AI makes decisions", "Privacy: data minimization, consent, right to be forgotten", "Responsible AI: safety, reliability, accountability"], handsOn: [{ task: "Audit a model for bias across different demographic groups.", hint: "Evaluate accuracy, FPR, FNR separately for each group; compare disparities." }, { task: "Implement fairness constraints in a classification model.", hint: "Equalized odds: ensure TPR and FPR are equal across groups; adjust thresholds." }] },
  { title: "Deployment", theory: "Deploying AI models makes them accessible in production. Key considerations: latency (response time), throughput (requests per second), cost, reliability, and monitoring.\n\nServing options: REST API (Flask, FastAPI), serverless (AWS Lambda), managed (SageMaker, Vertex AI), edge (TensorRT, ONNX). Model optimization: quantization (reduce precision), pruning (remove weights), distillation (train smaller model), ONNX (cross-platform). Monitoring: track latency, errors, data drift, model performance over time.", keyPoints: ["REST API: most common serving method (FastAPI)", "Quantization: reduce precision (FP32 → INT8) for speed", "Distillation: train small model to mimic large model", "Monitoring: latency, errors, data drift, performance decay", "A/B testing for model updates in production"], handsOn: [{ task: "Deploy an ML model as a REST API using FastAPI.", hint: "Load model in startup; create /predict endpoint; accept input, return prediction as JSON." }, { task: "Optimize model inference using ONNX Runtime and measure speedup.", hint: "Export to ONNX; load with onnxruntime; benchmark inference time vs original framework." }] }
];

export const mlopsTopics: TopicContent[] = [
  { title: "ML Pipelines", theory: "ML pipelines automate the end-to-end machine learning workflow: data ingestion → preprocessing → feature engineering → training → evaluation → deployment. They ensure reproducibility, scalability, and reliability.\n\nTools: Apache Airflow (general), Kubeflow Pipelines (Kubernetes-native), MLflow Pipelines, Prefect, Dagster. Each stage is a component with defined inputs/outputs. DAG (Directed Acyclic Graph) defines execution order. Pipelines enable: automated retraining, data validation, A/B testing, model monitoring.", keyPoints: ["Automate: data → preprocess → train → evaluate → deploy", "DAG defines component execution order", "Reproducibility: same data + code = same results", "Tools: Airflow, Kubeflow, MLflow, Prefect", "Enable automated retraining on schedule or trigger"], handsOn: [{ task: "Build an ML pipeline using MLflow or a similar framework.", hint: "Define stages as functions; log parameters, metrics, artifacts at each stage." }, { task: "Design a pipeline that automatically retrains when data drift is detected.", hint: "Monitor incoming data statistics; trigger retraining when distribution shift exceeds threshold." }] },
  { title: "Experiment Tracking", theory: "Experiment tracking records hyperparameters, metrics, code versions, and artifacts for each ML experiment. It enables comparison, reproduction, and auditing of experiments.\n\nKey features: parameter logging, metric tracking (loss, accuracy over time), artifact storage (models, plots), experiment comparison, reproducibility. Tools: MLflow Tracking, Weights & Biases, Neptune, Comet ML, TensorBoard. Best practices: track everything, use meaningful experiment names, tag experiments, log code versions.", keyPoints: ["Log: parameters, metrics, artifacts, code version", "Compare experiments across hyperparameter combinations", "MLflow: open-source, widely adopted", "W&B: collaborative, great visualizations", "Enable reproducibility: same params → same results"], handsOn: [{ task: "Set up experiment tracking with MLflow and log a complete training run.", hint: "mlflow.start_run(), mlflow.log_params(), mlflow.log_metrics(), mlflow.log_artifact()." }, { task: "Run a hyperparameter sweep and use tracking to find the best configuration.", hint: "Use grid/random search; log each combination; compare metrics in MLflow UI." }] },
  { title: "Model Versioning", theory: "Model versioning tracks different versions of trained models, their lineage (data + code + params), and promotion through stages (staging, production, archived).\n\nModel registry: centralized store for model versions with metadata. Each version records: training data version, code commit, hyperparameters, metrics, environment. Promotion workflow: train → evaluate → register → staging → production. Rollback: revert to previous version if new model underperforms. Tools: MLflow Model Registry, DVC, Weights & Biases.", keyPoints: ["Model registry: centralized version management", "Track lineage: data + code + params → model", "Stage transitions: staging → production → archived", "Rollback: revert to previous version if needed", "Semantic versioning: major.minor.patch for models"], handsOn: [{ task: "Set up a model registry and manage model lifecycle (stage transitions).", hint: "MLflow: mlflow.register_model(), transition_model_version_stage()." }, { task: "Implement a model comparison workflow that promotes the best model to production.", hint: "Compare new model metrics vs current production; promote if significantly better." }] },
  { title: "Feature Stores", theory: "Feature stores provide a centralized platform for storing, computing, and serving ML features. They ensure consistency between training and serving, enable feature reuse, and handle feature freshness.\n\nComponents: offline store (batch features for training), online store (low-latency serving), feature transformation logic, feature registry (discovery and documentation). Tools: Feast (open-source), Tecton, Databricks Feature Store, AWS SageMaker Feature Store. Key benefit: avoid training-serving skew (same feature computation in both environments).", keyPoints: ["Centralized feature management and serving", "Offline store: batch for training; Online store: real-time for serving", "Prevent training-serving skew", "Feature reuse across teams and models", "Tools: Feast (open-source), Tecton (managed)"], handsOn: [{ task: "Set up a feature store using Feast and define feature views.", hint: "Define entities, feature views with data sources, and materialize features." }, { task: "Serve features online for real-time prediction and compare with training features.", hint: "Use feast.get_online_features(); verify values match offline computation." }] },
  { title: "Model Serving", theory: "Model serving makes trained models available for inference in production. Requirements: low latency, high throughput, reliability, scalability, and cost efficiency.\n\nServing patterns: online (real-time API), batch (process many inputs), streaming (continuous processing). Frameworks: TensorFlow Serving, TorchServe, Triton Inference Server, BentoML, FastAPI. Optimization: model quantization, batching requests, GPU sharing, model caching. Scaling: horizontal (more instances) with load balancer, autoscaling based on traffic.", keyPoints: ["Online serving: REST/gRPC API for real-time predictions", "Batch serving: process large datasets periodically", "Triton: multi-framework, GPU-optimized serving", "Request batching: group requests for GPU efficiency", "Autoscaling: adjust instances based on traffic"], handsOn: [{ task: "Deploy a model using BentoML or FastAPI with proper error handling.", hint: "Define service, create API endpoint, handle input validation, return predictions." }, { task: "Load test your model API and identify performance bottlenecks.", hint: "Use locust or k6; measure p50, p95, p99 latency; find throughput limit." }] },
  { title: "Monitoring & Drift", theory: "ML monitoring ensures deployed models perform well over time. Data drift: input distribution changes. Concept drift: relationship between inputs and outputs changes. Both degrade model performance.\n\nMonitoring dimensions: model performance (accuracy, latency), data quality (missing values, schema), data drift (statistical tests), prediction distribution. Detection methods: KS test, PSI (Population Stability Index), JS divergence. Alerting: trigger retraining when drift exceeds thresholds. Tools: Evidently AI, WhyLabs, NannyML.", keyPoints: ["Data drift: input distribution changes over time", "Concept drift: input-output relationship changes", "KS test, PSI: statistical drift detection methods", "Monitor: performance metrics, data quality, prediction distribution", "Automate: alert + retrain when drift detected"], handsOn: [{ task: "Implement data drift detection using statistical tests on incoming data.", hint: "Compare feature distributions: KS test for continuous, chi-square for categorical." }, { task: "Set up a monitoring dashboard that tracks model performance over time.", hint: "Log predictions and actuals; compute rolling metrics; alert on degradation." }] },
  { title: "CI/CD for ML", theory: "CI/CD for ML extends traditional CI/CD to handle data, models, and experiments. It automates testing, training, validation, and deployment of ML systems.\n\nML-specific additions: data validation (schema checks, distribution tests), model testing (unit tests for preprocessing, integration tests for pipeline), model validation (performance thresholds, fairness checks), automated deployment (canary, blue-green). Tools: GitHub Actions + MLflow, DVC (data versioning), CML (Continuous Machine Learning), Jenkins.", keyPoints: ["CI: test code + data + model on every commit", "CD: automate model deployment when tests pass", "Data testing: schema validation, distribution checks", "Model testing: performance thresholds, fairness constraints", "CML: CI/CD specific to ML projects"], handsOn: [{ task: "Create a CI/CD pipeline for an ML project using GitHub Actions.", hint: "Steps: checkout → setup → install deps → validate data → train → evaluate → deploy if threshold met." }, { task: "Implement automated model testing with performance and fairness checks.", hint: "Assert accuracy > threshold; assert max group disparity < limit; fail deployment if not met." }] },
  { title: "Containerization", theory: "Containerization packages ML applications with all dependencies into portable, reproducible units. Docker containers ensure 'works on my machine' works everywhere.\n\nDockerfile for ML: base image (Python), install dependencies, copy code and model artifacts, define entrypoint. Docker Compose for multi-service setups (API + database + monitoring). Kubernetes orchestrates containers at scale: auto-scaling, load balancing, self-healing. GPU support: NVIDIA Container Toolkit for GPU access in containers.", keyPoints: ["Docker: package app + dependencies in portable container", "Reproducibility: same container = same behavior everywhere", "Multi-stage builds: separate build and runtime for smaller images", "Kubernetes: orchestrate containers at scale", "GPU containers: NVIDIA runtime for GPU access"], handsOn: [{ task: "Containerize an ML API with Docker and create a production-ready Dockerfile.", hint: "FROM python:3.11-slim → COPY → RUN pip install → COPY model → CMD uvicorn app:app." }, { task: "Create a Docker Compose setup with ML API, database, and monitoring.", hint: "Three services: api (your model), postgres (data), prometheus/grafana (monitoring)." }] },
  { title: "Cloud ML Services", theory: "Cloud platforms provide managed ML services that handle infrastructure: training, deployment, AutoML, and monitoring. They reduce operational burden but increase vendor lock-in.\n\nAWS: SageMaker (end-to-end), EC2/ECS (custom). GCP: Vertex AI (end-to-end), AI Platform. Azure: Azure ML. Key services: managed notebooks, distributed training, hyperparameter tuning, model hosting, AutoML. Cost optimization: spot/preemptible instances for training, serverless for intermittent inference, GPU types for different workloads.", keyPoints: ["SageMaker, Vertex AI: end-to-end managed ML platforms", "AutoML: automated model selection and tuning", "Spot instances: 60-90% cheaper for training", "Serverless inference: pay only when called", "Multi-cloud: avoid vendor lock-in when possible"], handsOn: [{ task: "Deploy a model on a cloud ML platform (SageMaker or Vertex AI).", hint: "Upload model artifact, create endpoint configuration, deploy endpoint, test with sample request." }, { task: "Compare costs of different deployment options: dedicated, serverless, spot.", hint: "Estimate: requests/day, latency needs, compute requirements. Calculate monthly cost for each." }] }
];

export const mathForMLTopics: TopicContent[] = [
  { title: "Linear Algebra", theory: "Linear algebra is the mathematics of vectors, matrices, and linear transformations. It's fundamental to ML: data is stored in matrices, neural networks are matrix multiplications, and PCA uses eigendecomposition.\n\nVectors: represent data points in n-dimensional space. Matrices: represent transformations, datasets, and weights. Key operations: dot product, matrix multiplication, transpose, inverse. Eigenvalues/eigenvectors: directions of maximum variance. SVD (Singular Value Decomposition): factorizes any matrix.", keyPoints: ["Vectors: data points in feature space", "Matrix multiplication: core operation in neural networks", "Dot product: measures similarity between vectors", "Eigendecomposition: find principal directions", "SVD: powerful factorization for dimensionality reduction"], codeExample: { language: "python", code: `import numpy as np\n\n# Matrix operations fundamental to ML\nA = np.array([[2, 1], [1, 3]])\n\n# Eigendecomposition\neigenvalues, eigenvectors = np.linalg.eigh(A)\nprint(f"Eigenvalues: {eigenvalues}")\nprint(f"Eigenvectors:\\n{eigenvectors}")\n\n# Verify: A × v = λ × v\nfor i in range(len(eigenvalues)):\n    v = eigenvectors[:, i]\n    lam = eigenvalues[i]\n    print(f"A·v = {A @ v}, λ·v = {lam * v}")  # Should be equal\n\n# SVD\nU, S, Vt = np.linalg.svd(A)\nprint(f"\\nSVD: U={U.shape}, S={S}, Vt={Vt.shape}")\nprint(f"Reconstruct: {U @ np.diag(S) @ Vt}")`, explanation: "Eigendecomposition and SVD — the mathematical tools behind PCA and many ML algorithms." }, handsOn: [{ task: "Implement matrix multiplication from scratch and verify against NumPy.", hint: "Triple nested loop: C[i][j] = sum(A[i][k] * B[k][j] for k in range(n))." }, { task: "Use SVD to compress an image by keeping only the top-k singular values.", hint: "Decompose each color channel with SVD; reconstruct using only top k components." }] },
  { title: "Calculus", theory: "Calculus provides the tools for optimization in ML. Derivatives measure rate of change; gradient descent uses derivatives to minimize loss functions.\n\nPartial derivatives: rate of change with respect to one variable. Gradient: vector of all partial derivatives (points in direction of steepest ascent). Chain rule: compute derivatives of composed functions (backpropagation). Second derivatives (Hessian): curvature information for advanced optimization. Integral calculus: probability distributions, expected values.", keyPoints: ["Derivative: rate of change, slope of function", "Gradient: vector of partial derivatives", "Chain rule: (f∘g)' = f'(g(x)) × g'(x)", "Gradient descent: move against gradient to minimize", "Hessian: matrix of second derivatives (curvature)"], handsOn: [{ task: "Implement gradient descent from scratch for a simple function f(x) = x² + 2x + 1.", hint: "Derivative: f'(x) = 2x + 2. Update: x = x - lr * f'(x). Iterate until convergence." }, { task: "Compute gradients of a neural network loss function using chain rule.", hint: "For L(σ(wx+b), y): ∂L/∂w = ∂L/∂ŷ × ∂ŷ/∂z × ∂z/∂w." }] },
  { title: "Probability", theory: "Probability theory provides the mathematical framework for uncertainty, which is fundamental to ML. Probabilistic models make predictions with confidence levels and handle noisy data.\n\nKey concepts: random variables, probability distributions (discrete: Bernoulli, Binomial, Poisson; continuous: Gaussian, Uniform, Exponential), joint/marginal/conditional probability. Bayes' theorem: P(A|B) = P(B|A)P(A)/P(B). Expected value: E[X] = Σ x·P(x). Law of large numbers: sample mean converges to expected value.", keyPoints: ["P(A|B) = P(B|A)P(A) / P(B) — Bayes' theorem", "Gaussian: most important distribution (Central Limit Theorem)", "Joint probability: P(A,B) = P(A|B)P(B)", "Expected value: weighted average of outcomes", "Independence: P(A,B) = P(A)P(B)"], handsOn: [{ task: "Implement a Naive Bayes classifier from scratch using Bayes' theorem.", hint: "P(class|features) ∝ P(class) × ∏P(feature|class). Assume feature independence." }, { task: "Simulate the Central Limit Theorem: sample means approach normal distribution.", hint: "Take many samples from any distribution; plot histogram of means → approaches Gaussian." }] },
  { title: "Statistics", theory: "Statistics provides methods for collecting, analyzing, and drawing conclusions from data. Descriptive statistics summarize data; inferential statistics make predictions about populations from samples.\n\nDescriptive: mean, median, mode, variance, standard deviation, percentiles, skewness, kurtosis. Inferential: confidence intervals, hypothesis testing, p-values. Distributions: normal, t, chi-square, F. Maximum Likelihood Estimation (MLE): find parameters that maximize the probability of observed data.", keyPoints: ["Mean, median, mode: measures of central tendency", "Variance, std: measures of spread", "Confidence interval: range containing true parameter", "MLE: find parameters maximizing data likelihood", "Central Limit Theorem: sample means → normal distribution"], handsOn: [{ task: "Compute descriptive statistics and visualize distributions of a dataset.", hint: "Use np.mean(), np.std(), np.percentile(); plot histograms and box plots." }, { task: "Implement Maximum Likelihood Estimation for a Gaussian distribution.", hint: "MLE for Gaussian: μ̂ = mean(data), σ̂² = mean((data - μ̂)²)." }] },
  { title: "Information Theory", theory: "Information theory quantifies information content and is crucial for understanding loss functions and decision trees. Entropy measures uncertainty; cross-entropy measures the difference between two distributions.\n\nEntropy: H(X) = -Σ p(x) log p(x). Higher entropy = more uncertainty. Cross-entropy: H(p,q) = -Σ p(x) log q(x) — measures how well q approximates p. KL Divergence: D_KL(p||q) = H(p,q) - H(p) — asymmetric distance between distributions. Mutual information: how much knowing one variable tells about another.", keyPoints: ["Entropy: H(X) = -Σ p(x)log p(x) — measures uncertainty", "Cross-entropy: loss function for classification", "KL Divergence: asymmetric distance between distributions", "Mutual information: shared information between variables", "Lower entropy = more predictable = more information gain"], handsOn: [{ task: "Calculate entropy and information gain for decision tree splitting.", hint: "Parent entropy - weighted child entropies = information gain. Pick feature with highest gain." }, { task: "Implement cross-entropy loss and verify it matches framework implementations.", hint: "CE = -Σ y_true × log(y_pred). Handle log(0) with small epsilon." }] },
  { title: "Optimization", theory: "Optimization finds the parameters that minimize (or maximize) an objective function. ML training is fundamentally an optimization problem: minimize the loss function.\n\nConvex optimization: single global minimum, guaranteed convergence. Non-convex: multiple local minima, saddle points (common in deep learning). Gradient descent variants: batch, mini-batch, stochastic. Second-order methods: Newton's method (uses Hessian), L-BFGS. Constrained optimization: Lagrange multipliers (used in SVM). Convergence: learning rate, momentum, adaptive methods.", keyPoints: ["Gradient descent: move in direction of steepest descent", "Convex: one minimum; Non-convex: multiple local minima", "Learning rate: step size (too big = diverge, too small = slow)", "Saddle points: more problematic than local minima in high dimensions", "Constrained optimization: Lagrange multipliers for SVM"], handsOn: [{ task: "Visualize gradient descent on a 2D function with different learning rates.", hint: "Plot contours of f(x,y); overlay GD path for lr = 0.001, 0.01, 0.1." }, { task: "Compare convergence of SGD, SGD+Momentum, and Adam on a non-convex function.", hint: "Create a function with multiple minima; run each optimizer; compare convergence speed." }] },
  { title: "Matrix Decomposition", theory: "Matrix decomposition breaks matrices into products of simpler matrices. It's fundamental to dimensionality reduction, recommender systems, and solving linear systems.\n\nLU Decomposition: A = LU (lower × upper triangular), for solving linear systems. QR Decomposition: A = QR (orthogonal × upper triangular), for least squares. Eigendecomposition: A = QΛQ⁻¹, for PCA. SVD: A = UΣV^T, most versatile (works for any matrix). Cholesky: A = LL^T (for positive definite matrices, used in GP).", keyPoints: ["SVD: A = UΣVᵀ, works for any matrix", "Eigendecomposition: for square symmetric matrices (PCA)", "LU: efficient for solving systems of equations", "QR: numerically stable for least squares", "Cholesky: for positive definite matrices (efficient)"], handsOn: [{ task: "Implement PCA using eigendecomposition and SVD, compare results.", hint: "Eigendecomposition of covariance matrix vs SVD of centered data. Same principal components." }, { task: "Build a simple recommender system using matrix factorization (SVD).", hint: "Decompose user-item rating matrix; predict missing ratings using low-rank approximation." }] },
  { title: "Bayesian Inference", theory: "Bayesian inference updates beliefs about parameters given observed data. Prior (initial belief) + Likelihood (data evidence) → Posterior (updated belief). P(θ|data) ∝ P(data|θ) × P(θ).\n\nConjugate priors simplify computation (e.g., Beta-Binomial, Normal-Normal). MCMC (Markov Chain Monte Carlo) samples from complex posteriors. Bayesian approaches provide uncertainty estimates, handle small data well, and avoid overfitting through priors. MAP (Maximum A Posteriori) is a point estimate combining prior and likelihood.", keyPoints: ["Posterior ∝ Likelihood × Prior", "Conjugate prior: posterior has same form as prior", "MCMC: sample from complex posteriors", "Bayesian: provides uncertainty estimates naturally", "MAP: maximum of posterior (regularized MLE)"], handsOn: [{ task: "Implement Bayesian inference for coin flip estimation with a Beta prior.", hint: "Prior: Beta(α, β). After h heads, t tails: Posterior = Beta(α+h, β+t). Plot distributions." }, { task: "Compare MLE vs MAP estimation and show how the prior affects the result.", hint: "MLE: pure data-driven. MAP: pulled toward prior. With little data, prior dominates." }] },
  { title: "Hypothesis Testing", theory: "Hypothesis testing determines whether observed effects are statistically significant. It's used to validate ML experiments, A/B tests, and model comparisons.\n\nProcess: State H₀ (null) and H₁ (alternative) → Choose significance level α → Compute test statistic → Calculate p-value → Reject or fail to reject H₀. Common tests: z-test (known σ), t-test (unknown σ), chi-square (categorical), ANOVA (multiple groups), paired t-test (before/after). Multiple testing correction: Bonferroni, FDR.", keyPoints: ["H₀: no effect; H₁: there is an effect", "p-value: probability of data given H₀ is true", "α = 0.05: reject H₀ if p-value < α", "Type I error: false positive (reject true H₀)", "Type II error: false negative (fail to reject false H₀)"], handsOn: [{ task: "Conduct a paired t-test to compare two ML models' performance.", hint: "Run both models on same folds; paired t-test on accuracy differences; check p-value." }, { task: "Implement the Bonferroni correction for testing multiple hypotheses.", hint: "Adjusted α = α / number_of_tests. Apply to each individual test." }] }
];
